import { spawn } from "child_process";
import { createServer } from "http";
import path from "path";
import fs from "fs";
import os from "os";

const CONFIG_FILE = path.join(os.homedir(), ".claudecode", "stream-relay-config");

export class StreamRelayManager {
  constructor() {
    this.process = null;
    this.port = null;
    this.enabled = false;
    this.restartAttempts = 0;
    this.maxRestartAttempts = 5;
    this.restartDelay = 2000;
  }

  async findAvailablePort() {
    return new Promise((resolve, reject) => {
      const server = createServer();
      server.listen(0, "127.0.0.1", () => {
        const port = server.address().port;
        server.close(() => resolve(port));
      });
      server.on("error", reject);
    });
  }

  async start(dirPath, quietMode, log, serverBase) {
    try {
      this.port = await this.findAvailablePort();
      const statsPort = await this.findAvailablePort();

      const streamRelayQuiet = process.env.STREAM_RELAY_QUIET === "1";

      const env = {
        ...process.env,
        LISTEN_PORT: this.port.toString(),
        STATS_PORT: statsPort.toString(),
        STREAM_RELAY_QUIET: streamRelayQuiet ? "1" : "0",
        PIPE_BROTLI: "1",
        PIPE_BODYDICT: "1",
        PIPE_PROFILE: "1",
        PIPE_BSON: "1",
        SERVER_BASE: `${serverBase.replace(/\/$/, "")}/stream-relay`,
        UPSTREAM_BASE: "http://gac",
      };

      this.process = spawn("node", [path.join(dirPath, "stream-relay.cjs")], {
        env,
        stdio: ["ignore", "pipe", "pipe"],
      });

      this.process.stdout.on("data", (data) => {
        if (!quietMode) {
          process.stdout.write(`[stream-relay] ${data}`);
        }
      });

      this.process.stderr.on("data", (data) => {
        if (!quietMode) {
          process.stderr.write(`[stream-relay] ${data}`);
        }
      });

      this.process.on("exit", (code) => {
        if (this.enabled && code !== 0) {
          this.handleCrash(quietMode, log);
        }
      });

      this.process.on("error", (err) => {
        console.error(`[stream-relay] Failed to start: ${err.message}`);
        if (this.enabled) {
          this.handleCrash(quietMode, log);
        }
      });

      return { port: this.port, statsPort };
    } catch (err) {
      console.error(`[stream-relay] Failed to start: ${err.message}`);
      if (this.enabled) {
        this.handleCrash(quietMode, log);
      }
    }
  }

  handleCrash(quietMode, log) {
    this.restartAttempts++;
    if (this.restartAttempts > this.maxRestartAttempts) {
      console.error(
        `[stream-relay] Max restart attempts (${this.maxRestartAttempts}) exceeded, giving up.`
      );
      this.enabled = false;
      return;
    }

    log(
      `[stream-relay] Crashed, restarting in ${this.restartDelay}ms (attempt ${this.restartAttempts}/${this.maxRestartAttempts})`
    );

    setTimeout(() => {
      this.start(quietMode, log);
    }, this.restartDelay);
  }

  stop() {
    if (this.process) {
      this.process.kill("SIGTERM");
      this.process = null;
    }
    this.enabled = false;
  }
}

export function isStreamRelayEnabled() {
  try {
    if (fs.existsSync(CONFIG_FILE)) {
      const config = JSON.parse(fs.readFileSync(CONFIG_FILE, "utf-8"));
      return config.enabled === true;
    }
  } catch (err) {
    // Silently ignore
  }
  return false;
}

export function enableStreamRelay() {
  const configDir = path.dirname(CONFIG_FILE);
  if (!fs.existsSync(configDir)) {
    fs.mkdirSync(configDir, { recursive: true });
  }
  fs.writeFileSync(CONFIG_FILE, JSON.stringify({ enabled: true }, null, 2));
}

export function disableStreamRelay() {
  if (fs.existsSync(CONFIG_FILE)) {
    fs.unlinkSync(CONFIG_FILE);
  }
}
